import{_ as i,o as a,c as r,a1 as o}from"./chunks/framework.BmLW0N4k.js";const c=JSON.parse('{"title":"経済・収入最適化ガイド","description":"","frontmatter":{},"headers":[],"relativePath":"guide/economy-guide.md","filePath":"guide/economy-guide.md"}'),t={name:"guide/economy-guide.md"};function e(n,l,s,h,u,g){return a(),r("div",null,[...l[0]||(l[0]=[o('<h1 id="経済・収入最適化ガイド" tabindex="-1">経済・収入最適化ガイド <a class="header-anchor" href="#経済・収入最適化ガイド" aria-label="Permalink to &quot;経済・収入最適化ガイド&quot;">​</a></h1><blockquote><p>このページはインターネット上の攻略情報を集約した内容です。未検証の情報を含む場合があります。</p></blockquote><hr><h2 id="収入の基本原則" tabindex="-1">収入の基本原則 <a class="header-anchor" href="#収入の基本原則" aria-label="Permalink to &quot;収入の基本原則&quot;">​</a></h2><p>Anno 117の通貨は<strong>デナリウス</strong>。画面上部に「現在の所持金」と「収支（毎分の増減）」が表示されます。<strong>収支をプラスに保つこと</strong>が経済運営の最優先目標で、プラスを維持できていれば大きな出費がない限り資金は時間とともに増えていきます。</p><p>主な収入源:</p><ol><li><strong>住民からの税収</strong> — 最も信頼できる主力収入。初期から終盤までの基本収入。</li><li><strong>生産建物の収入範囲効果</strong> — 居住区に隣接させて発生させる受動収入。</li><li><strong>交易</strong> — 余剰品の自動販売・交易ルート・契約報酬。</li></ol><p><strong>急成長注意:</strong> 住居を上位ティアに早期アップグレードすると、満たすべき需要（必要な生産チェーン）が増え、未充足だと税収ボーナスが伸びず、上位需要用の建物の維持費だけが増えて赤字化します。</p><ul><li><strong>配置効率:</strong> あるサービス建物の効果範囲内の住居枠を、まず住居で埋め切ってからアップグレードする。範囲あたりの税収を維持費に対して最大化できます。</li><li><strong>レイアウト:</strong> 中央に幅広の「メインストリート」を通し、そこに公共施設などのサービス建物を集約。住区はそこから<strong>T字型</strong>に伸ばすと効果範囲のカバー効率が高くなります。</li><li><strong>道路の質:</strong> 舗装道・大理石の道は輸送効率をアップさせるだけでなく、公共サービスの範囲効果もアップさせます。</li></ul><h3 id="序盤の方針" tabindex="-1">序盤の方針 <a class="header-anchor" href="#序盤の方針" aria-label="Permalink to &quot;序盤の方針&quot;">​</a></h3><ul><li>序盤は住居の建設と、住民を満足させるアメニティ整備に時間を割く。税収と生産収入が主収入になります。</li><li>「ゆっくり建てる」のが基本。Annoは忍耐と緩やかな拡大のゲームです。</li><li>余剰労働力を健全に保つ。労働力こそが最大の税収源です。</li><li>ゲームを一時停止して都市計画し、必要な数だけ建築しましょう。必須需要のお粥・イワシ等は3〜4セットを先に計画しておくと安定します。</li></ul><hr><h2 id="税収の最大化" tabindex="-1">税収の最大化 <a class="header-anchor" href="#税収の最大化" aria-label="Permalink to &quot;税収の最大化&quot;">​</a></h2><h3 id="需要充足ボーナス" tabindex="-1">需要充足ボーナス <a class="header-anchor" href="#需要充足ボーナス" aria-label="Permalink to &quot;需要充足ボーナス&quot;">​</a></h3><p>税額は固定ではなく、<strong>各住居について満たした「需要」1つごとにボーナスが加算されます</strong>。ティアが上がるほど需要の数が増え、各ボーナスの価値も高くなります。</p><p>1家あたりの税ボーナスの例:</p><ul><li>チュニック（糸紡ぎ師） +1</li><li>ピレウス帽（ピレウス帽職人） +1</li><li>ガルム（ガルム工房） +1 ただし健康-2</li></ul><h3 id="収入範囲効果" tabindex="-1">収入範囲効果 <a class="header-anchor" href="#収入範囲効果" aria-label="Permalink to &quot;収入範囲効果&quot;">​</a></h3><p>多くの生産施設は、効果範囲内の建物のパラメーターを上げる「範囲効果」を持ちます。<strong>ただし、その建物が実際に生産稼働している間しか効果が出ません</strong>（倉庫満杯や原料切れで生産が止まるとボーナスも即停止）。</p><h3 id="税収を伸ばす配置・研究のコツ" tabindex="-1">税収を伸ばす配置・研究のコツ <a class="header-anchor" href="#税収を伸ばす配置・研究のコツ" aria-label="Permalink to &quot;税収を伸ばす配置・研究のコツ&quot;">​</a></h3><ul><li>収入・人口にプラス属性を持つ生産建物を<strong>住区のすぐ近く</strong>に置く（倉庫範囲も考慮）。人口も増え、さらに収入もプラスされます。</li><li>マイナス効果も考慮して、見張りで火災安全度、医院で健康度も相殺するとよいでしょう。</li></ul><hr><h2 id="維持費の管理" tabindex="-1">維持費の管理 <a class="header-anchor" href="#維持費の管理" aria-label="Permalink to &quot;維持費の管理&quot;">​</a></h2><p>赤字の典型原因は<strong>拡大しすぎ</strong>。「住居と生産施設を増やす→維持費が増える→収入を増やさない→さらに施設を増やす…」の悪循環で資金が尽きます。収支が赤に振れたら、<strong>高コストの生産建物を一時停止</strong>して立て直しましょう。</p><ul><li>立て直しの場つなぎで船を建造してNPCに売ってしのぐのもアリです。</li></ul><h3 id="維持費削減テクニック" tabindex="-1">維持費削減テクニック <a class="header-anchor" href="#維持費削減テクニック" aria-label="Permalink to &quot;維持費削減テクニック&quot;">​</a></h3><ul><li>兵士を野営させると軍維持費 <strong>-80%</strong>。</li><li>建物の効果範囲を広げる研究で、必要なサービス建物の数を削減。</li><li>倉庫をアップグレードするより2軒建てる方が効率的な場合があります。</li><li>道路を舗装すると必要な倉庫数が減ります。</li></ul><h3 id="専門家による削減・増収" tabindex="-1">専門家による削減・増収 <a class="header-anchor" href="#専門家による削減・増収" aria-label="Permalink to &quot;専門家による削減・増収&quot;">​</a></h3><p>専門家は<strong>総督のヴィラ</strong>や<strong>オフィキウム</strong>のスロット（名声の数値により増減）に装着し、その建物の周囲範囲にバフを与えます。専門家自体は維持費を取らず、いつでも付け替え可能です。</p><p>経済関連の専門家の例:</p><p><strong>収入アップ系</strong></p><ul><li>「引退した徴税人」アミュンタス（Legendary）: 収入 +2</li><li>「利益を追い求めるパトリキ」アウロス・ペクニウス・マグヌス（Epic）: 収入 +1.8</li><li>「無比の勘定役」アクティウス・マクシミヌス（Unique）: 維持費 -75%・範囲効果 収入 +1.5</li><li>「金の学士」アウロス・ラニウス（Epic）: 範囲効果 収入 +1.5</li></ul><p><strong>維持費削減系</strong></p><ul><li>「型破りな職人」（Rare）／「収集家」（Common）: 維持費 -50%・労働力維持費 -25%</li><li>「水の管理人」アクイラ・ドゥルシス（Legendary）: 維持費 -30%（水道供給・防火ボーナスあり）</li><li>「マルス・ルーケティウスへの改宗者」アウン（Legendary）／「大いに祝福されしブライアン」（Legendary）: 維持費 -25%</li><li>「補給係」（Common）: 維持費 -50%・労働力維持費 -25%</li></ul><p><strong>生産強化系</strong></p><ul><li>「奇妙な鍛冶師」アネイリン・グワードリッド（Legendary）: 生産性 +25%・追加生産あり</li><li>「仕立て屋のイオリア人」（Epic）: 竪琴チェーン 生産性 +35%</li><li>「車輪技師」（Rare）: 戦車チェーン 生産性 +20%</li></ul><h3 id="信仰神による経済バフ" tabindex="-1">信仰神による経済バフ <a class="header-anchor" href="#信仰神による経済バフ" aria-label="Permalink to &quot;信仰神による経済バフ&quot;">​</a></h3><p>信仰する神により経済効果が異なります:</p><ul><li><strong>ケレース（農業の女神）</strong>: 必要な農場数が減る／住居あたり人口密度↑。</li><li><strong>ネプトゥーヌス（海）</strong>: 船の維持費を最大 <strong>-50%</strong>。</li><li><strong>メルクリウス（交易）</strong>: 受動的交易の利益性が向上。</li><li><strong>マルス（戦争）</strong>: 軍・徴兵の維持費削減。</li></ul><hr><h2 id="生産バランス" tabindex="-1">生産バランス <a class="header-anchor" href="#生産バランス" aria-label="Permalink to &quot;生産バランス&quot;">​</a></h2><h3 id="監視ツール" tabindex="-1">監視ツール <a class="header-anchor" href="#監視ツール" aria-label="Permalink to &quot;監視ツール&quot;">​</a></h3><ul><li>画面右上の<strong>毎分収入</strong>表示。プラス=黒字、マイナス=破産接近。</li><li><strong>統計メニュー</strong>で消費と生産の比率を確認。消費が生産に迫ってきたら増設して欠品を防ぎましょう。</li></ul><h3 id="_100-効率の生産チェーン比率" tabindex="-1">100%効率の生産チェーン比率 <a class="header-anchor" href="#_100-効率の生産チェーン比率" aria-label="Permalink to &quot;100%効率の生産チェーン比率&quot;">​</a></h3><p>研究・専門家・祭礼・宗教などのブースト無しの素の生産速度に基づく値です:</p><p><strong>Tier1（リベルトゥス）</strong></p><ul><li>板材: 木こり 1 + 製材所 1</li><li>お粥: オーツ麦農場 1 + お粥の屋台 1</li><li>チュニック: 大麻農場 1 + 糸紡ぎ師 1</li></ul><p><strong>Tier2（プレブス）</strong></p><ul><li>パン: 小麦農場 2 + 粉ひき所 1 + パン屋 2 + 炭焼き師 0.5</li><li>武器: 鉄鉱山 1 + 溶鉱炉 2 + 武器工房 3 + 炭焼き師 1.25</li><li>オリーブオイル: オリーブ農家 4 + オリーブ圧搾所 3</li></ul><p><strong>Tier3（エクィテス）</strong></p><ul><li>ワイン: ブドウ園 2 + 養蜂場 1 + ワイン醸造所 1</li><li>トガ: 亜麻農場 3 + カタツムリ飼育場 3 + 織物工房 4 + 染色工房 4 + 織機工 2</li></ul><p><strong>Tier4（パトリキ）</strong></p><ul><li>ネックレス: 鉱物の採石場 3 + 鉱物粉砕所 4 + 金鉱 10 + 金細工工房 4 + 宝石商 6 + 炭焼き師 2.5</li></ul><h3 id="住民ティアと必要需要-ラティウム" tabindex="-1">住民ティアと必要需要（ラティウム） <a class="header-anchor" href="#住民ティアと必要需要-ラティウム" aria-label="Permalink to &quot;住民ティアと必要需要（ラティウム）&quot;">​</a></h3><ul><li><strong>リベルトゥス（Tier1）</strong>: お粥（オーツ麦農場+お粥の屋台）、チュニック（大麻農場+糸紡ぎ師）、漁師小屋の食料（イワシ）、市場の公共サービス。詳細は<a href="/wiki/population.html">住民層</a>を参照。</li><li><strong>プレブス（Tier2）</strong>: パン（小麦→粉ひき所→パン屋）またはガルム、サンダルまたは石鹸、瓦（粘土穴→瓦窯）など。</li></ul><blockquote><p><strong>労働力の注意:</strong> 住居を上位ティアにアップグレードすると、その家のリベルトゥス労働力が減り、プレブス労働力が増えます（リベルトゥス -2、プレブス +1）。基礎産業を維持するため、<strong>アップグレードと並行して新規リベルトゥス住居を建て続けること</strong>。</p></blockquote><hr><h2 id="交易での利益" tabindex="-1">交易での利益 <a class="header-anchor" href="#交易での利益" aria-label="Permalink to &quot;交易での利益&quot;">​</a></h2><h3 id="受動的交易" tabindex="-1">受動的交易 <a class="header-anchor" href="#受動的交易" aria-label="Permalink to &quot;受動的交易&quot;">​</a></h3><ul><li>交易所で各商品の<strong>最低在庫しきい値</strong>を設定すると、それを超えた余剰がNPCへ自動販売されます。</li><li>資源を枯渇させないため、最低在庫数を適切に設定しましょう。</li><li>信仰神メルクリウスや研究で受動的交易の利益性が上がります。</li></ul><h3 id="能動的交易" tabindex="-1">能動的交易 <a class="header-anchor" href="#能動的交易" aria-label="Permalink to &quot;能動的交易&quot;">​</a></h3><ul><li>交易ルートメニューから手動でルートを組み、高値で売却。ラティウムとアルビオン間など<strong>属州をまたぐ輸送</strong>で、各地域固有の需要（チーズ・ブローチ等）を融通します。</li><li>高値が付きやすい交易品の例: 馬・武器・高級品</li><li>プレイヤー報告の相場例: <ul><li>オリーブオイル／石鹸／ガルム を ドリアン に 1個 60〜74（大口で最大100個まで）。</li><li>ワイン等はアルビオンのNPCと無限取引可能で安定収入。</li><li>NPCトレーダーのクエスト（例: イワシ40個 → 4,000デナリウス）。</li><li>NPCの港から安く買って転売する<strong>裁定取引</strong>。</li></ul></li></ul><h3 id="契約・救済" tabindex="-1">契約・救済 <a class="header-anchor" href="#契約・救済" aria-label="Permalink to &quot;契約・救済&quot;">​</a></h3><ul><li>NPCの灯台で<strong>契約</strong>: 2万デナリウス超の一括報酬＋貴重な専門家を獲得できる場合があります。</li><li>ゲーム設定で「救済を許可」を有効にすると財政難時に資金援助を受けられますが、ゲーム難度によりゲームオーバーになる場合があります。</li></ul><hr><h2 id="クイック・チェックリスト-赤字脱出" tabindex="-1">クイック・チェックリスト（赤字脱出） <a class="header-anchor" href="#クイック・チェックリスト-赤字脱出" aria-label="Permalink to &quot;クイック・チェックリスト（赤字脱出）&quot;">​</a></h2><ol><li>拡大を止め、収支がプラスに戻るまで様子を見る。</li><li>原料切れ・倉庫満杯で<strong>止まっている生産建物</strong>を解消（範囲効果復活）。</li><li>高維持費の生産建物を一時停止。</li><li>住民の需要不足を埋め、収入プラスの範囲効果建物（糸紡ぎ師・パン屋・漁師小屋など）を居住区中心に配置。</li><li>ゲーム速度を最速にして黒字状態を回す。</li><li>余剰品の受動的交易の最低在庫を見直す。</li><li>専門家で維持費削減（-50%系）・収入アップをヴィラ・オフィキウムに装着。</li><li>船を建造し、NPCの港で売却する。</li><li>NPCが無制限に購入してくれる品物を売却する黒字航路を作成する（取引価格補正の専門家があるとさらに有効）。</li></ol>',67)])])}const p=i(t,[["render",e]]);export{c as __pageData,p as default};
